+            "/tmp/one/shared".to_string()
+        );
+        assert_eq!(rows[1].get_named::<i64>("created_at").unwrap(), 1);
+        assert_eq!(rows[2].get_named::<i64>("id").unwrap(), 3);
+        assert_eq!(
